When('I capture the driveaway price from ROAP', async function () {
  const variant = this.roapVariant || '';
  const engine = this.roapEngine || '';
  const transmission = this.roapTransmission || '';
  assert.ok(variant && engine && transmission,
    `Missing row criteria (variant="${variant}", engine="${engine}", transmission="${transmission}"). Earlier steps must run first.`);

  console.log(`🔎 Finding ROAP row matching Variant="${variant}", Engine="${engine}", Transmission="${transmission}"`);
  await this.page.waitForLoadState('networkidle', { timeout: 10000 }).catch(() => {});
  await this.page.waitForTimeout(500);

  // Locate the body row whose cells contain all three criteria and tag it so
  // Playwright can target it.
  const matchInfo = await this.page.evaluate(({ variant, engine, transmission }) => {
    function visible(el) {
      const r = el.getBoundingClientRect();
      if (r.width === 0 || r.height === 0) return false;
      const cs = window.getComputedStyle(el);
      return cs.visibility !== 'hidden' && cs.display !== 'none';
    }
    function norm(s) { return (s || '').replace(/\s+/g, ' ').trim().toLowerCase(); }
    function rowText(row) {
      const cells = row.querySelectorAll('td, [role="cell"], [class*="cell" i]');
      return Array.from(cells).map(c => norm(c.textContent)).filter(Boolean);
    }
    const wantV = norm(variant), wantE = norm(engine), wantT = norm(transmission);

    // Try classic <tbody><tr>, then role-based row groups.
    const rowSets = [
      Array.from(document.querySelectorAll('tbody tr')).filter(visible),
      Array.from(document.querySelectorAll('[role="row"]')).filter(visible),
      Array.from(document.querySelectorAll('tr')).filter(visible),
    ];
    const samples = [];
    for (const rows of rowSets) {
      for (const row of rows) {
        const cells = rowText(row);
        if (cells.length === 0) continue;
        const joined = cells.join(' | ');
        if (samples.length < 12) samples.push(joined);
        const hit = (w) => cells.some(c => c === w || c.includes(w));
        if (hit(wantV) && hit(wantE) && hit(wantT)) {
          row.setAttribute('data-roap-target', '1');
          return { ok: true, cells };
        }
      }
      if (rows.length > 0) break; // don't fall through if we already saw rows
    }
    return { ok: false, samples };
  }, { variant, engine, transmission });

  if (!matchInfo.ok) {
    throw new Error(`No ROAP row matched all three criteria. Sample rows seen: ${JSON.stringify(matchInfo.samples)}`);
  }
  console.log(`📋 Matched row cells: ${JSON.stringify(matchInfo.cells)}`);

  const matchedRow = this.page.locator('[data-roap-target="1"]').first();
  await matchedRow.scrollIntoViewIfNeeded({ timeout: 3000 }).catch(() => {});

  // Click the row checkbox (leftmost cell) to expand the package sub-row.
  // Fall back to clicking the row itself if no checkbox is found.
  const rowCheckbox = matchedRow.locator('input[type="checkbox"]').first();
  if ((await rowCheckbox.count()) > 0) {
    const checked = await rowCheckbox.isChecked().catch(() => false);
    if (!checked) {
      // The visible click target is often a custom wrapper around the input.
      await rowCheckbox.click({ force: true, timeout: 5000 }).catch(async () => {
        await matchedRow.click({ timeout: 5000 });
      });
    }
  } else {
    await matchedRow.click({ timeout: 5000 });
  }
  await this.page.waitForTimeout(800);
  await this.page.waitForLoadState('networkidle', { timeout: 10000 }).catch(() => {});

  // After expanding, the Driveaway package row appears immediately under the
  // matched row, e.g. "Driveaway $20,111 (142)". Search the DOM for that
  // pattern; fall back to the right-side details panel.
  const captured = await this.page.evaluate(() => {
    function visible(el) {
      const r = el.getBoundingClientRect();
      if (r.width === 0 || r.height === 0) return false;
      const cs = window.getComputedStyle(el);
      return cs.visibility !== 'hidden' && cs.display !== 'none';
    }
    const driveawayPriceRe = /drive\s*-?\s*away[^$]*\$\s*([\d,]+(?:\.\d{1,2})?)/i;
    const all = Array.from(document.querySelectorAll('body *')).filter(visible);
    // Prefer the smallest containing element (most specific).
    const matches = [];
    for (const el of all) {
      const t = (el.textContent || '').replace(/\s+/g, ' ').trim();
      if (!t || t.length > 200) continue;
      const m = t.match(driveawayPriceRe);
      if (m) {
        const r = el.getBoundingClientRect();
        matches.push({ text: t, price: m[1], area: r.width * r.height });
      }
    }
    if (matches.length === 0) return { error: 'No "Driveaway $..." text found after row expand.' };
    matches.sort((a, b) => a.area - b.area);
    return { text: matches[0].price, context: matches[0].text };
  });

  if (captured.error) {
    throw new Error(captured.error);
  }
  const num = Number.parseFloat(String(captured.text).replace(/[^0-9.]/g, ''));
  if (!Number.isFinite(num)) {
    throw new Error(`Captured driveaway value "${captured.text}" is not a number.`);
  }
  this.roapDriveawayPrice = num;
  this.roapDriveawayPriceText = `$${captured.text}`;
  console.log(`📌 Captured ROAP Driveaway price: $${captured.text} (from: "${captured.context}")`);

  // Save a dedicated screenshot of the ROAP page so it's included in the
  // report alongside the consumer-site one (mirrors PIM's behaviour).
  try {
    const dir = 'screenshots';
    if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
    const vehicleTag = (this.driveawayPriceData?.[0]?.Vehicle || 'ROAP')
      .toString().replace(/[^a-zA-Z0-9]/g, '_');
    const ts = new Date().toISOString().replace(/[:.]/g, '-');
    const file = path.join(dir, `roap-Driveaway-${vehicleTag}-${ts}.png`);
    const buf = await this.page.screenshot({ fullPage: true });
    fs.writeFileSync(file, buf);
    if (typeof this.attach === 'function') this.attach(buf, 'image/png');
    this.roapScreenshotPath = file;
    console.log(`📸 ROAP Driveaway screenshot saved: ${file}`);
  } catch (err) {
    console.warn(`⚠️  Failed to save ROAP screenshot: ${err.message}`);
  }

  // Clean up the tag so it doesn't linger for the next scenario.
  await this.page.evaluate(() => {
    document.querySelectorAll('[data-roap-target]').forEach(el => el.removeAttribute('data-roap-target'));
  }).catch(() => {});
});

When('I navigate to the calculator page', async function () {
  // Read CPC URL from the "Driveaway Price - Test Data" sheet loaded by
  // the Background step.
  const row = (this.driveawayPriceData || [])[0] || {};
  const target = (row['CPC URL'] || row.CPCURL || row.cpc_url || row.cpcUrl || row.CpcUrl || row.URL || row.url || '').toString().trim();
  assert.ok(/^https?:\/\//i.test(target), `CPC URL is not a valid http(s) URL: "${target}". Check the "Driveaway Price - Test Data" sheet has a CPC URL value.`);

  // Setup network intercept listeners (captures all requests/responses for this page)
  if (!this._networkInterceptSetup) {
    this.networkRequests = [];
    this.networkResponses = [];
    this.page.on('request', (req) => {
      (this.networkRequests = this.networkRequests || []).push({ url: req.url(), method: req.method() });
    });
    this.page.on('response', async (res) => {
      (this.networkResponses = this.networkResponses || []).push({ url: res.url(), status: res.status() });
    });
    this._networkInterceptSetup = true;
    console.log('📡 Network intercept listeners active');
  }

  // Capture the variantpricecalc XHR — its response has the authoritative
  // `finalDriveAwayPrice` value, more reliable than DOM scraping. Also push
  // the raw XHR into _capturedApiPayloads so the report's payload panel
  // shows the full request/response (mirrors PIM's MLP capture).
  if (!this._cpcVariantPriceCalcListenerSetup) {
    this.cpcDriveawayFromNetwork = null;
    this.page.on('response', async (resp) => {
      try {
        if (!/variantpricecalc/i.test(resp.url())) return;
        if (!resp.ok()) return;
        const bodyText = await resp.text().catch(() => '');
        let json = null;
        try { json = bodyText ? JSON.parse(bodyText) : null; } catch { /* not JSON */ }
        if (json && typeof json.finalDriveAwayPrice === 'number') {
          this.cpcDriveawayFromNetwork = json.finalDriveAwayPrice;
        }
        try {
          const req = resp.request();
          const payload = {
            url: resp.url(),
            method: req.method(),
            requestBody: '',
            requestHeaders: req.headers() || {},
            statusCode: resp.status(),
            responseHeaders: resp.headers() || {},
            responseBody: bodyText,
            timestamp: new Date().toISOString(),
            source: 'roap-variantpricecalc',
          };
          if (Array.isArray(this._capturedApiPayloads)) {
            this._capturedApiPayloads.push(payload);
          }
        } catch { /* ignore */ }
      } catch { /* ignore */ }
    });
    this._cpcVariantPriceCalcListenerSetup = true;
  }

  console.log(`📋 Navigating to calculator: ${target}`);
  await this.page.goto(target, { waitUntil: 'domcontentloaded', timeout: 60000 });
  await this.page.waitForLoadState('networkidle', { timeout: 30000 }).catch(() => {});
  await this.page.waitForTimeout(2000);
});

// ─── Calculator page (consumer site) ────────────────────────────────────────
// These steps mirror PIM_auto.steps.js's consumer-site flow. The Hyundai
// calculator opens a "Set your location" modal on first visit — postcode,
// suburb and Set-dealer are all handled by the shared `handleLocationModal`
// helper, so we trigger it from the postcode step. The two follow-up steps
// then become no-ops because the modal is already dismissed.

function _isNa(v) {
  if (!v) return true;
  const s = String(v).trim().toLowerCase();
  return s === '' || s === 'na' || s === 'n/a' || s === '-';
}

