Then('I verify the captured driveaway price matches on calculator page', async function () {
  const roapPrice = this.roapDriveawayPrice;
  assert.ok(Number.isFinite(roapPrice),
    'ROAP Driveaway price was not captured — the capture step must run first.');

  // The authoritative consumer value comes from the variantpricecalc XHR
  // response (finalDriveAwayPrice). Give any in-flight request a brief
  // window to land, then fall back to scraping the popup if necessary.
  if (!Number.isFinite(this.cpcDriveawayFromNetwork)) {
    await this.page
      .waitForResponse(r => /variantpricecalc/i.test(r.url()) && r.ok(), { timeout: 8000 })
      .catch(() => null);
  }
  await this.page.waitForLoadState('networkidle', { timeout: 5000 }).catch(() => {});
  await this.page.waitForTimeout(800);

  let cpcPrice = null;
  let source = '';
  if (Number.isFinite(this.cpcDriveawayFromNetwork)) {
    cpcPrice = this.cpcDriveawayFromNetwork;
    source = 'network (variantpricecalc.finalDriveAwayPrice)';
  } else {
    const captured = await this.page.evaluate(() => {
      function visible(el) {
        const r = el.getBoundingClientRect();
        if (r.width === 0 || r.height === 0) return false;
        const cs = window.getComputedStyle(el);
        return cs.visibility !== 'hidden' && cs.display !== 'none';
      }
      const labelRe = /drive\s*-?\s*away|driveaway/i;
      const all = Array.from(document.querySelectorAll('body *')).filter(visible);
      const hits = [];
      for (const el of all) {
        const t = (el.textContent || '').replace(/\s+/g, ' ').trim();
        if (!t || t.length > 200) continue;
        if (!labelRe.test(t)) continue;
        const m = t.match(/\$\s*([\d,]+(?:\.\d{1,2})?)/);
        if (!m) continue;
        const r = el.getBoundingClientRect();
        hits.push({ text: t, price: m[1], area: r.width * r.height });
      }
      if (hits.length === 0) return { error: 'No "Driveaway $..." text found on calculator price summary.' };
      hits.sort((a, b) => a.area - b.area);
      return { text: hits[0].price, context: hits[0].text };
    });
    if (captured.error) throw new Error(captured.error);
    cpcPrice = Number.parseFloat(String(captured.text).replace(/[^0-9.]/g, ''));
    assert.ok(Number.isFinite(cpcPrice), `Calculator driveaway "${captured.text}" is not a number.`);
    source = `popup DOM ("${captured.context}")`;
  }

  this.cpcDriveawayPrice = cpcPrice;
  console.log(`📌 Calculator Driveaway price: $${cpcPrice.toLocaleString()} [source: ${source}]`);
  console.log(`📊 Comparison — ROAP: $${roapPrice.toLocaleString()}  |  Calculator: $${cpcPrice.toLocaleString()}`);

  // Compare whole-dollar amounts only (ignore cent rounding differences).
  assert.strictEqual(
    Math.trunc(cpcPrice),
    Math.trunc(roapPrice),
    `Driveaway price mismatch — ROAP $${roapPrice} vs Calculator $${cpcPrice}`
  );
  console.log('✅ Driveaway prices match (whole-dollar).');
});
